import{_ as a,o as t,c as d,a4 as n}from"./chunks/framework.Cqne-ChA.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-alt.md","filePath":"reference/zopen-alt.md","lastUpdated":1776692264000}'),o={name:"reference/zopen-alt.md"};function i(r,e,p,l,s,v){return t(),d("div",null,[...e[0]||(e[0]=[n('<div class="man-page-content" data-v-3eed99e3><h1 align="center" data-v-3eed99e3>ZOPEN-ALT</h1><h2 data-v-3eed99e3>NAME <a name="NAME" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>zopen-alt − manual page for zopen-alt 0.8.4</p><h2 data-v-3eed99e3>SYNOPSIS <a name="SYNOPSIS" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3><b data-v-3eed99e3>zopen-alt</b> [<i data-v-3eed99e3>OPTION</i>] [<i data-v-3eed99e3>PACKAGE</i>] [<i data-v-3eed99e3>PARAMETERS</i>]...</p><h2 data-v-3eed99e3>DESCRIPTION <a name="DESCRIPTION" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>zopen−alt is a utility for zopen community to switch package versions for currently installed packages.</p><h2 data-v-3eed99e3>OPTIONS <a name="OPTIONS" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3><b data-v-3eed99e3>−h</b>, <b data-v-3eed99e3>−−help</b>, −?</p><p style="margin-left:22%;" data-v-3eed99e3>display this help and exit.</p><p style="margin-left:11%;" data-v-3eed99e3><b data-v-3eed99e3>−−select</b> [PACKAGE]</p><p style="margin-left:22%;" data-v-3eed99e3>select the active version for PACKAGE from a list.</p><p style="margin-left:11%;" data-v-3eed99e3><b data-v-3eed99e3>−s</b>, <b data-v-3eed99e3>−−set</b> [PACKAGE] [VERSION]</p><p style="margin-left:22%;" data-v-3eed99e3>set the active version for PACKAGE to VERSION.</p><p style="margin-left:11%;" data-v-3eed99e3><b data-v-3eed99e3>−v</b>, <b data-v-3eed99e3>−−verbose</b></p><p style="margin-left:22%;" data-v-3eed99e3>run in verbose mode.</p><p style="margin-left:11%;" data-v-3eed99e3><b data-v-3eed99e3>−−version</b></p><p style="margin-left:22%;" data-v-3eed99e3>print version</p><h2 data-v-3eed99e3>EXAMPLES <a name="EXAMPLES" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>zopen alt foo</p><p style="margin-left:22%;" data-v-3eed99e3>list the available alternatives for package ’foo’</p><p style="margin-left:11%;" data-v-3eed99e3>zopen alt −−select foo</p><p style="margin-left:22%;" data-v-3eed99e3>list the available alternatives for package ’foo’ and allow the user to select an alternative version</p><p style="margin-left:11%;" data-v-3eed99e3>zopen alt −−set foo foo−1.2.3.19700101_012345.zos</p><p style="margin-left:22%;" data-v-3eed99e3>set the active version of package ’foo’ to version foo−1.2.3.19700101_012345.zos if available</p><h2 data-v-3eed99e3>AUTHOR <a name="AUTHOR" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p><h2 data-v-3eed99e3>REPORTING BUGS <a name="REPORTING BUGS" data-v-3eed99e3></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>Report bugs at https://github.com/zopencommunity/meta/issues</p><p style="margin-left:11%;margin-top:1em;" data-v-3eed99e3>This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p></div>',1)])])}const c=a(o,[["render",i],["__scopeId","data-v-3eed99e3"]]);export{f as __pageData,c as default};
